using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_6d0effe6c6de4edca19984acdb468c2b;

public class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);

        return Task.FromResult(new AuthenticationState(user));
    }
}

@page "/profile"
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@attribute [Authorize(Roles = "Editor")]
@rendermode InteractiveAuto

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the editor page. You have the Editor role.</p>

@page "/viewer"
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<p>Welcome! This page is accessible to any authenticated user.</p>

