using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_6d0effe6c6de4edca19984acdb468c2b.Client;

namespace sv_6d0effe6c6de4edca19984acdb468c2b;

public class HardcodedAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private static readonly Task<AuthenticationState> AuthStateTask;
    private readonly PersistingComponentStateSubscription _subscription;

    static HardcodedAuthenticationStateProvider()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        AuthStateTask = Task.FromResult(new AuthenticationState(user));
    }

    public HardcodedAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _subscription = persistentState.RegisterOnPersisting(
            () =>
            {
                persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Email = "bob@example.com",
                    Roles = ["User", "Editor"],
                });
                return Task.CompletedTask;
            },
            RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => AuthStateTask;

    public void Dispose() => _subscription.Dispose();
}

